public final class HybridFileProviderUtil {
    private HybridFileProviderUtil() {}

    @NonNull
    public static Uri createImageUri(Context context, String authority) throws IOException {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.Q) {
            ContentValues values = new ContentValues();
            values.put(MediaStore.Images.Media.DISPLAY_NAME, "IMG_" + System.currentTimeMillis() + ".jpg");
            values.put(MediaStore.Images.Media.MIME_TYPE, "image/jpeg");
            values.put(MediaStore.Images.Media.RELATIVE_PATH, Environment.DIRECTORY_PICTURES + "/HybridMVP");
            Uri uri = context.getContentResolver().insert(MediaStore.Images.Media.EXTERNAL_CONTENT_URI, values);
            if (uri == null) throw new IOException("Failed to create MediaStore record");
            return uri;
        } else {
            File dir = context.getExternalFilesDir(Environment.DIRECTORY_PICTURES);
            if (dir == null) dir = context.getCacheDir();
            File f = File.createTempFile("IMG_" + System.currentTimeMillis() + "_", ".jpg", dir);
            return FileProvider.getUriForFile(context, authority, f);
        }
    }
}

